.aplus-v2 {
      displayblock;
      margin-leftauto;
      margin-rightauto;
      word-wrap break-word;
      overflow-wrap break-word;
      word-break break-word;
    }

    /* Undo this for tech-specs because it breaks table layout */
    .aplus-v2 .aplus-standard .aplus-tech-spec-table { word-break initial; }
    .aplus-v2 .aplus-standard .aplus-module-wrapper {text-aligninherit; displayblock; margin-rightauto;margin-leftauto;}
    .aplus-v2 .aplus-standard.aplus-module.module-1,
    .aplus-v2 .aplus-standard.aplus-module.module-2,
    .aplus-v2 .aplus-standard.aplus-module.module-3,
    .aplus-v2 .aplus-standard.aplus-module.module-4,
    .aplus-v2 .aplus-standard.aplus-module.module-6,
    .aplus-v2 .aplus-standard.aplus-module.module-7,
    .aplus-v2 .aplus-standard.aplus-module.module-8,
    .aplus-v2 .aplus-standard.aplus-module.module-9,
    .aplus-v2 .aplus-standard.aplus-module.module-10,
    .aplus-v2 .aplus-standard.aplus-module.module-11,
    .aplus-v2 .aplus-standard.aplus-module.module-12{padding-bottom12px; margin-bottom12px;}
    .aplus-v2 .aplus-standard.aplus-modulelast-child{border-bottomnone}
    .aplus-v2 .aplus-standard.aplus-module {min-width979px;}

    /* aplus css needed to override aui on the detail page */
    .aplus-v2 .aplus-standard.aplus-module table.aplus-chart.a-bordered.a-vertical-stripes {bordernone;}
    .aplus-v2 .aplus-standard.aplus-module table.aplus-chart.a-bordered.a-vertical-stripes td {backgroundnone;}
    .aplus-v2 .aplus-standard.aplus-module table.aplus-chart.a-bordered.a-vertical-stripes td.selected {background-color#ffd;}
    .aplus-v2 .aplus-standard.aplus-module table.aplus-chart.a-bordered.a-vertical-stripes tdfirst-child {background#f7f7f7; font-weightbold;}
    .aplus-v2 .aplus-standard.aplus-module table.aplus-chart.a-bordered.a-vertical-stripes tr th {backgroundnone; border-rightnone;}
    .aplus-v2 .aplus-standard.aplus-module table.aplus-chart.a-bordered tr td,.aplus-v2 .aplus-standard .aplus-module table.aplus-chart.a-bordered tr th {border-bottom1px dotted #999;}

    /* A+ Template - General Module CSS */
    .aplus-v2 .aplus-standard .apm-top {height100%; vertical-aligntop;}
    html[dir='rtl'] .aplus-v2 .aplus-standard .apm-top {padding-left 0px; padding-right 3px}
    .aplus-v2 .aplus-standard .apm-center {height100%; vertical-alignmiddle; text-aligncenter;}
    .aplus-v2 .aplus-standard .apm-text-center {text-aligncenter;}
    .aplus-v2 .aplus-standard .apm-row {width100%; displayinline-block;}
    .aplus-v2 .aplus-standard .apm-wrap {width100%;}
    .aplus-v2 .aplus-standard .apm-fixed-width {width969px;}
    .aplus-v2 .aplus-standard .apm-floatleft {floatleft;}
    html[dir='rtl'] .aplus-v2 .aplus-standard .apm-floatleft {floatright;}
    .aplus-v2 .aplus-standard .apm-floatright {floatright;}
    html[dir='rtl'] .aplus-v2 .aplus-standard .apm-floatright {floatleft;}
    .aplus-v2 .aplus-standard .apm-floatnone {floatnone;}
    .aplus-v2 .aplus-standard .apm-spacing img {bordernone;}
    .aplus-v2 .aplus-standard .apm-leftimage {floatleft; displayblock; margin-right20px; margin-bottom10px;width 300px;}
    html[dir='rtl'] .aplus-v2 .aplus-standard .apm-leftimage {float right; margin-right 0px; margin-left20px;}
    .aplus-v2 .aplus-standard .apm-centerimage {text-align center; width300px; displayblock; margin-bottom10px;}
    .aplus-v2 .aplus-standard .apm-centerthirdcol {min-width359px; displayblock}
    .aplus-v2 .aplus-standard .apm-centerthirdcol ul,
    .aplus-v2 .aplus-standard .apm-centerthirdcol ol {margin-left 334px;}
    html[dir='rtl'] .aplus-v2 .aplus-standard .apm-centerthirdcol ul,
    html[dir='rtl'] .aplus-v2 .aplus-standard .apm-centerthirdcol ol {margin-left 0px; margin-right 334px;}
    .aplus-v2 .aplus-standard .apm-rightthirdcol {floatright; width230px; padding-left30px; margin-left30px; border-left1px solid #dddddd;}
    html[dir='rtl'] .aplus-v2 .aplus-standard .apm-rightthirdcol {float left; padding-left 0px; padding-right30px; margin-left0px; margin-right30px; border-left0px; border-right1px solid #dddddd;}
    .aplus-v2 .aplus-standard .apm-lefttwothirdswrap {width709px; displayblock;}
    .aplus-v2 .aplus-standard .apm-lefthalfcol {width480px; padding-right30px; displayblock; floatleft;}
    html[dir='rtl'] .aplus-v2 .aplus-standard .apm-lefthalfcol {padding-left30px; floatright;}
    .aplus-v2 .aplus-standard .apm-righthalfcol {width480px; displayblock; floatleft;}
    html[dir='rtl'] .aplus-v2 .aplus-standard .apm-righthalfcol {floatright;}
    .aplus-v2 .aplus-standard .apm-eventhirdcol {width300px; displayblock;}
    .aplus-v2 .aplus-standard .apm-eventhirdcol-table {border-spacing 0px 0px; border-collapse collapse;}
    .aplus-v2 .aplus-standard .apm-eventhirdcol-table tr td {vertical-align top;}
    .aplus-v2 .aplus-standard .apm-fourthcol {width220px; floatleft;}
    html[dir='rtl'] .aplus-v2 .aplus-standard .apm-fourthcol {floatright;}
    .aplus-v2 .aplus-standard .apm-fourthcol .apm-fourthcol-image {positionrelative;}
    .aplus-v2 .aplus-standard .apm-fourthcol img {displayblock; margin0 auto;}
    .aplus-v2 .aplus-standard .apm-fourthcol-table {border-spacing 0px 0px; border-collapse collapse;}
    .aplus-v2 .aplus-standard .apm-fourthcol-table tr td {vertical-align top;}
    .aplus-v2 .aplus-standard .apm-listbox {width100%;}
    .aplus-v2 .aplus-standard .apm-iconheader {floatleft; padding-left10px;}
    html[dir='rtl'] .aplus-v2 .aplus-standard .apm-iconheader {floatright; padding-left0px; padding-right 10px}
    .aplus-v2 .aplus-standard .apm-spacing ullast-child,.aplus-v2 .aplus-standard ollast-child {margin-bottom0 !important;}
    .aplus-v2 .aplus-standard .apm-spacing ul,.aplus-v2 .aplus-standard ol {padding0 !important;}
